import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"发布资源","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/publishing.md","filePath":"zh/guide/publishing.md"}'),t={name:"zh/guide/publishing.md"};function n(h,a,c,o,d,p){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="发布资源" tabindex="-1">发布资源 <a class="header-anchor" href="#发布资源" aria-label="Permalink to &quot;发布资源&quot;">​</a></h1><p>Clearance 通过 <code>vendor:publish</code> 标签发布三类资源：配置、迁移和翻译文件。配置和迁移由安装程序自动处理（参见<a href="/clearance-docs/zh/guide/installation.html">安装</a>）；本页介绍如何手动发布它们，以及如何发布翻译文件。</p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>将 <code>config/clearance.php</code> 发布到你的应用中。每一个键及其默认值和用途，请参见<a href="/clearance-docs/zh/guide/configuration.html">配置参考</a>。</p><h2 id="翻译" tabindex="-1">翻译 <a class="header-anchor" href="#翻译" aria-label="Permalink to &quot;翻译&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>这会将内置的 9 种语言（<code>ar</code>、<code>en</code>、<code>es</code>、<code>fr</code>、<code>hi</code>、<code>it</code>、<code>pt</code>、<code>ru</code>、<code>zh</code>）复制到你应用中的 <code>lang/vendor/clearance/{locale}/ui.php</code>。要添加新语言或覆盖某个现有语言中的字符串，请在该目录下新增一个语言目录，并以 <code>en/ui.php</code> 作为规范的键参考。所有语言都暴露完全相同的键集合，并在每次变更时都通过一个专门的测试进行验证。</p><h2 id="覆盖面板布局" tabindex="-1">覆盖面板布局 <a class="header-anchor" href="#覆盖面板布局" aria-label="Permalink to &quot;覆盖面板布局&quot;">​</a></h2><p><code>layout</code> 配置键控制全页组件所使用的 Blade 布局：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>保持为 <code>null</code> 以使用你应用的默认 Livewire 布局，或将其设置为一个特定的布局视图，以便在自定义外壳中渲染面板。</p><h2 id="迁移" tabindex="-1">迁移 <a class="header-anchor" href="#迁移" aria-label="Permalink to &quot;迁移&quot;">​</a></h2><p>Clearance 的迁移由 <code>php artisan clearance:install</code> 自动发布并运行——如果 <code>roles</code> 表尚不存在，安装程序还会先发布并运行 Spatie 的迁移。完整的分步流程请参见<a href="/clearance-docs/zh/guide/installation.html">安装</a>，以及其中关于切勿在全新环境中直接运行 <code>migrate</code> 的<a href="/clearance-docs/zh/guide/installation.html#运行安装程序">危险提示</a>。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/guide/configuration.html">配置参考</a>——每一个配置键</li><li><a href="/clearance-docs/zh/guide/installation.html">安装</a>——完整的安装程序流程</li><li><a href="/clearance-docs/zh/guide/migration.html">迁移</a>——为已有的 Spatie 安装使用 <code>clearance:backfill</code></li></ul>`,16)])])}const k=e(t,[["render",n]]);export{u as __pageData,k as default};
